def ford_fulkerson(arr: list[int]) -> int:
    n = arr[0]
    m = arr[1]
    src = arr[2]
    sink = arr[3]
    cap = [[0] * n for _ in range(n)]
    for i in range(m):
        cap[arr[4 + 3 * i]][arr[5 + 3 * i]] += arr[6 + 3 * i]

    def dfs(u, t, flow, visited):
        if u == t:
            return flow
        visited[u] = True
        for v in range(n):
            if not visited[v] and cap[u][v] > 0:
                d = dfs(v, t, min(flow, cap[u][v]), visited)
                if d > 0:
                    cap[u][v] -= d
                    cap[v][u] += d
                    return d
        return 0

    max_flow = 0
    while True:
        visited = [False] * n
        flow = dfs(src, sink, float('inf'), visited)
        if flow == 0:
            break
        max_flow += flow
    return max_flow

fn dfs_ff(u: usize, sink: usize, flow: i32, visited: &mut Vec<bool>, cap: &mut Vec<Vec<i32>>, n: usize) -> i32 {
    if u == sink { return flow; }
    visited[u] = true;
    for v in 0..n {
        if !visited[v] && cap[u][v] > 0 {
            let d = dfs_ff(v, sink, flow.min(cap[u][v]), visited, cap, n);
            if d > 0 { cap[u][v] -= d; cap[v][u] += d; return d; }
        }
    }
    0
}

pub fn ford_fulkerson(arr: &[i32]) -> i32 {
    let n = arr[0] as usize; let m = arr[1] as usize;
    let src = arr[2] as usize; let sink = arr[3] as usize;
    let mut cap = vec![vec![0i32; n]; n];
    for i in 0..m { cap[arr[4+3*i] as usize][arr[5+3*i] as usize] += arr[6+3*i]; }
    let mut max_flow = 0;
    loop {
        let mut visited = vec![false; n];
        let flow = dfs_ff(src, sink, i32::MAX, &mut visited, &mut cap, n);
        if flow == 0 { break; }
        max_flow += flow;
    }
    max_flow
}

object FordFulkerson {
  private var capS: Array[Array[Int]] = _
  private var nS: Int = 0

  private def dfsS(u: Int, sink: Int, flow: Int, visited: Array[Boolean]): Int = {
    if (u == sink) return flow
    visited(u) = true
    for (v <- 0 until nS) {
      if (!visited(v) && capS(u)(v) > 0) {
        val d = dfsS(v, sink, math.min(flow, capS(u)(v)), visited)
        if (d > 0) { capS(u)(v) -= d; capS(v)(u) += d; return d }
      }
    }
    0
  }

  def fordFulkerson(arr: Array[Int]): Int = {
    nS = arr(0); val m = arr(1); val src = arr(2); val sink = arr(3)
    capS = Array.ofDim[Int](nS, nS)
    for (i <- 0 until m) capS(arr(4+3*i))(arr(5+3*i)) += arr(6+3*i)
    var maxFlow = 0
    var continue_ = true
    while (continue_) {
      val visited = new Array[Boolean](nS)
      val flow = dfsS(src, sink, Int.MaxValue, visited)
      if (flow == 0) continue_ = false
      else maxFlow += flow
    }
    maxFlow
  }
}

private var capSFF: [[Int]] = []
private var nSFF = 0

private func dfsSFF(_ u: Int, _ sink: Int, _ flow: Int, _ visited: inout [Bool]) -> Int {
    if u == sink { return flow }
    visited[u] = true
    for v in 0..<nSFF {
        if !visited[v] && capSFF[u][v] > 0 {
            let d = dfsSFF(v, sink, min(flow, capSFF[u][v]), &visited)
            if d > 0 { capSFF[u][v] -= d; capSFF[v][u] += d; return d }
        }
    }
    return 0
}

func fordFulkerson(_ arr: [Int]) -> Int {
    nSFF = arr[0]; let m = arr[1]; let src = arr[2]; let sink = arr[3]
    capSFF = [[Int]](repeating: [Int](repeating: 0, count: nSFF), count: nSFF)
    for i in 0..<m { capSFF[arr[4+3*i]][arr[5+3*i]] += arr[6+3*i] }
    var maxFlow = 0
    while true {
        var visited = [Bool](repeating: false, count: nSFF)
        let flow = dfsSFF(src, sink, Int.max, &visited)
        if flow == 0 { break }
        maxFlow += flow
    }
    return maxFlow
}

let capFF: number[][];
let nFF: number;

function dfsFF(u: number, sink: number, flow: number, visited: boolean[]): number {
    if (u === sink) return flow;
    visited[u] = true;
    for (let v = 0; v < nFF; v++) {
        if (!visited[v] && capFF[u][v] > 0) {
            const d = dfsFF(v, sink, Math.min(flow, capFF[u][v]), visited);
            if (d > 0) { capFF[u][v] -= d; capFF[v][u] += d; return d; }
        }
    }
    return 0;
}

export function fordFulkerson(arr: number[]): number {
    nFF = arr[0]; const m = arr[1]; const src = arr[2]; const sink = arr[3];
    capFF = Array.from({ length: nFF }, () => new Array(nFF).fill(0));
    for (let i = 0; i < m; i++) capFF[arr[4+3*i]][arr[5+3*i]] += arr[6+3*i];
    let maxFlow = 0;
    while (true) {
        const visited = new Array(nFF).fill(false);
        const flow = dfsFF(src, sink, Infinity, visited);
        if (flow === 0) break;
        maxFlow += flow;
    }
    return maxFlow;
}
